import type { Item, Customer, Policy } from './types.js';

const MAIN_ITEM_PRICES: Record<string, { insured: number; premium: number }> = {
  sword: { insured: 1000, premium: 100 },
  amulet: { insured: 600, premium: 60 },
  staff: { insured: 800, premium: 80 },
  potion: { insured: 400, premium: 40 },
};

const COMPONENT_INSURED = 250;
const COMPONENT_PREMIUM = 25;
const COMPONENT_TRIO_PREMIUM = 60;
const PROCESSING_FEE = 5;

function isComponent(type: string): boolean {
  return !(type in MAIN_ITEM_PRICES);
}

function itemSurchargeMultiplier(cursed: boolean, enchantment: number): number {
  let m = 1;
  if (cursed) m += 0.5;
  if (enchantment >= 5) m += 0.3;
  return m;
}

function calculateInsuranceSum(items: Item[]): number {
  return items.reduce((sum, item) => {
    return sum + (isComponent(item.type) ? COMPONENT_INSURED : MAIN_ITEM_PRICES[item.type].insured);
  }, 0);
}

export function quote(
  items: Item[],
  customer: Customer,
  contractNumber: number,
): { premium: number; policy: Policy } {
  const mainItems = items.filter((item) => !isComponent(item.type));
  const componentItems = items.filter((item) => isComponent(item.type));

  // Main items
  let totalBasePremium = 0;
  for (const item of mainItems) {
    const base = MAIN_ITEM_PRICES[item.type].premium;
    totalBasePremium += base * itemSurchargeMultiplier(item.cursed, item.enchantment);
  }

  // Components: group by type, apply trio pricing
  const componentGroups = new Map<string, Item[]>();
  for (const item of componentItems) {
    if (!componentGroups.has(item.type)) componentGroups.set(item.type, []);
    componentGroups.get(item.type)!.push(item);
  }

  for (const components of componentGroups.values()) {
    const trios = Math.floor(components.length / 3);
    const remainder = components.length % 3;

    // Each trio: base premium 60 G with surcharges derived from the trio's components
    for (let t = 0; t < trios; t++) {
      const trioItems = components.slice(t * 3, t * 3 + 3);
      const anyCursed = trioItems.some((c) => c.cursed);
      const maxEnchantment = Math.max(...trioItems.map((c) => c.enchantment));
      totalBasePremium += COMPONENT_TRIO_PREMIUM * itemSurchargeMultiplier(anyCursed, maxEnchantment);
    }

    // Remaining singles
    for (let s = 0; s < remainder; s++) {
      const item = components[trios * 3 + s];
      totalBasePremium += COMPONENT_PREMIUM * itemSurchargeMultiplier(item.cursed, item.enchantment);
    }
  }

  // Customer-level modifiers
  const isFirstContract = contractNumber === 1;
  const isLongStanding = customer.yearsWithMHPCO >= 2;

  let customerMultiplier = 1;
  customerMultiplier += isFirstContract ? 0.1 : -0.15;
  if (isLongStanding) customerMultiplier -= 0.2;

  const premiumBeforeFee = totalBasePremium * customerMultiplier;

  // Processing fee added after multiplier; round up (MHPCO's favor)
  const finalPremium = Math.ceil(premiumBeforeFee + PROCESSING_FEE);

  const insuranceSum = calculateInsuranceSum(items);
  const policy: Policy = {
    items,
    insuranceSum,
    remainingCap: insuranceSum * 2,
  };

  return { premium: finalPremium, policy };
}

