    const { payout } = processClaim(policy, [damage('amulet', 80)]);
    expect(payout).toBe(0);
  });

  it('returns 0 exactly when damage equals deductible', () => {
    const policy = makePolicy();
    const { payout } = processClaim(policy, [damage('amulet', 100)]);
    expect(payout).toBe(0);
  });
});

