const tsx = join(__dirname, '..', 'node_modules', '.bin', 'tsx');
const cli = join(__dirname, '..', 'src', 'cli.ts');

const result = spawnSync(tsx, [cli], {
  stdio: 'inherit',
  env: process.env,
});

process.exit(result.status ?? 1);
